/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWCobranca-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CreCliCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCliCod EndIf
If not (&CreVenCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vendedor") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVenCod EndIf
If not (&CreRecPag.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Receber/Pagar") If Not &CreRecPag.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreRecPag.EnumerationDescription() Endif EndIf
If not (&CreVlrSdo.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Saldo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreVlrSdo EndIf
If not (&CreSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "") If Not &CreSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreSts.EnumerationDescription() Endif EndIf
If not (&CreFrpPgtoTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cre Frp Pgto Tip") If Not &CreFrpPgtoTip.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CreFrpPgtoTip.EnumerationDescription() Endif EndIf If not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vct.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaVct WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaVct_To EndIf
If not (&CreDtaCob.IsEmpty() AND &CreDtaCob_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cobrado") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CreDtaCob WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CreDtaCob_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro1) EndIf Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCliRaz1.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz1) EndIf Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom1) EndIf Case &DynamicFiltersSelector1 = !'CRECBRCOD' &CreCbrCod1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "L.C. Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCbrCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro2) EndIf Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCliRaz2.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz2) EndIf Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom2) EndIf Case &DynamicFiltersSelector2 = !'CRECBRCOD' &CreCbrCod2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "L.C. Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCbrCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "DP. Número", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreDupNro3) EndIf Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCliRaz3.FromString(&GridStateDynamicFilter.Value) If not &CreCliRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Cliente", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCliRaz3) EndIf Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "L.C. Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CreCbrNom3) EndIf Case &DynamicFiltersSelector3 = !'CRECBRCOD' &CreCbrCod3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "L.C. Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CreCbrCod3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Vencto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Saldo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Cobrado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Prometeu" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Vend." &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "L. Cob." &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "Filial"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreRecPag (CreDtaVct) CreVlrSdo CreCliCod when &OrderedBy = 1 order CreDtaVct when &OrderedBy = 2 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 2 AND &OrderedDsc = True order CreDupNro when &OrderedBy = 3 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 3 AND &OrderedDsc = True order CreVlrSdo when &OrderedBy = 4 AND &OrderedDsc = False order (CreVlrSdo) when &OrderedBy = 4 AND &OrderedDsc = True order CreVlrDup when &OrderedBy = 5 AND &OrderedDsc = False order (CreVlrDup) when &OrderedBy = 5 AND &OrderedDsc = True order CreDtaCob when &OrderedBy = 6 AND &OrderedDsc = False order (CreDtaCob) when &OrderedBy = 6 AND &OrderedDsc = True order CreDtaProPagHor when &OrderedBy = 7 AND &OrderedDsc = False order (CreDtaProPagHor) when &OrderedBy = 7 AND &OrderedDsc = True order CreVenCod when &OrderedBy = 8 AND &OrderedDsc = False order (CreVenCod) when &OrderedBy = 8 AND &OrderedDsc = True order CreCbrCod when &OrderedBy = 9 AND &OrderedDsc = False order (CreCbrCod) when &OrderedBy = 9 AND &OrderedDsc = True order CrePedCod when &OrderedBy = 10 AND &OrderedDsc = False order (CrePedCod) when &OrderedBy = 10 AND &OrderedDsc = True order FilCod when &OrderedBy = 11 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWCobranca(&CreCliCod, &CreVenCod, &CreRecPag, &CreVlrSdo, &CreSts, &CreFrpPgtoTip , &DynamicFiltersSelector1, &DynamicFiltersOperator1, &CreDupNro1, &CreCliRaz1, &CreCbrNom1, &CreCbrCod1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2, &CreDupNro2, &CreCliRaz2, &CreCbrNom2 , &CreCbrCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CreDupNro3, &CreCliRaz3 , &CreCbrNom3, &CreCbrCod3, &CreDtaVct, &CreDtaVct_To, &CreDtaCob, &CreDtaCob_To)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(CreCliCodRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = CreDtaVct &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(CreDupNro) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = CreVlrSdo &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = CreVlrDup &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = CreDtaCob &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Date = CreDtaProPagHor &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = CreVenCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Number = CreCbrCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Number = CrePedCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Number = FilCod
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCobrancaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCobrancaGridState")) Else &GridState.FromXml(&Session.Get(!"WWCobrancaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVENCOD" &CreVenCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFRPPGTOTIP" &CreFrpPgtoTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CREDTACOB" &CreDtaCob.FromString(&GridStateFilterValue.Value) &CreDtaCob_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
